import React, { useState } from "react";

const DesignerForm = ({ onSubmit, existingData, onCancel }) => {
  const [formData, setFormData] = useState(
    existingData || { name: "", email: "", type: "video editing", previousDesigns: "" }
  );

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const formattedData = {
      ...formData,
      previousDesigns: formData.previousDesigns.split(",").map((d) => d.trim()),
    };
    onSubmit(formattedData);
    setFormData({ name: "", email: "", type: "video editing", previousDesigns: "" });
  };

  return (
    <form className="form" onSubmit={handleSubmit}>
      <h3>{existingData ? "Update Designer" : "Add Designer"}</h3>
      <input name="name" placeholder="Name" value={formData.name} onChange={handleChange} required />
      <input name="email" placeholder="Email" value={formData.email} onChange={handleChange} required />
      <select name="type" value={formData.type} onChange={handleChange}>
        <option value="video editing">Video Editing</option>
        <option value="image editing">Image Editing</option>
      </select>
      <input
        name="previousDesigns"
        placeholder="Previous Designs (comma separated links)"
        value={formData.previousDesigns}
        onChange={handleChange}
      />
      <button type="submit">{existingData ? "Update" : "Add"}</button>
      {onCancel && <button onClick={onCancel} type="button" className="cancel-btn">Cancel</button>}
    </form>
  );
};

export default DesignerForm;
